def _materialize_embedded_logo(key: str) -> str | None:
    """Create a temporary logo file from embedded fallback data when PNGs are not present."""
    data = EMBEDDED_LOGOS.get(key)
    if not data:
        return None
    path = os.path.join(tempfile.gettempdir(), f"winter_league_embedded_{key}.png")
    if not os.path.exists(path):
        try:
            with open(path, "wb") as f:
                f.write(base64.b64decode(data))
        except Exception:
            return None
    return path


def find_default_logo_path(key: str) -> str | None:
    """Find a logo next to the app file, in cwd, in /mnt/data, or use embedded fallback."""
    filename = LOGO_FILENAMES.get(key)
    if not filename:
        return None
    candidates = []
    try:
        candidates.append(os.path.join(os.path.dirname(os.path.abspath(__file__)), filename))
    except Exception:
        pass
    candidates.extend([
        os.path.join(os.getcwd(), filename),
        os.path.join('/mnt/data', filename),
    ])
    for candidate in candidates:
        if candidate and os.path.exists(candidate):
            return candidate
    return _materialize_embedded_logo(key)


def prepare_logo_paths(logo_uploads: dict | None = None) -> dict:
    paths = {}
    logo_uploads = logo_uploads or {}
    for key in LOGO_FILENAMES:
        upload = logo_uploads.get(key)
        if upload is not None:
            suffix = os.path.splitext(LOGO_FILENAMES[key])[1] or '.png'
            tmp = tempfile.NamedTemporaryFile(delete=False, suffix=suffix)
            try:
                tmp.write(upload.getvalue())
            except Exception:
                tmp.write(upload.read())
            tmp.close()
            paths[key] = tmp.name
        else:
            default_path = find_default_logo_path(key)
            if default_path:
                paths[key] = default_path
    return paths


def team_logo_key(team: str) -> str | None:
    return TEAM_LOGO_KEYS.get(normalize_team_name(team))


