def safe_draw_image(c, path, x, y, w, h):
    if not path or not os.path.exists(path):
        return False
    try:
        c.drawImage(ImageReader(path), x, y, width=w, height=h, preserveAspectRatio=True, mask='auto')
        return True
    except Exception:
        return False


def draw_team_logo(c, logo_paths, team, x, y, w=13, h=13):
    """Draw team logos with a small size boost for Estrellas, whose mark reads small in tables."""
    key = team_logo_key(team)
    path = logo_paths.get(key)
    if not path:
        return False
    if key == "estrellas":
        return safe_draw_image(c, path, x - 1.5, y - 1.5, w + 5, h + 5)
    return safe_draw_image(c, path, x, y, w, h)


def draw_wrapped_text(c, text, x, y, width, font="Helvetica", size=8, color="#111111", leading=10, max_lines=6):
    c.setFillColor(colors.HexColor(color))
    c.setFont(font, size)
    avg_char = max(size * 0.47, 3.2)
    max_chars = max(20, int(width / avg_char))
    lines = []
    for para in str(text).split('\n'):
        lines.extend(textwrap.wrap(para, max_chars) or [""])
    for line in lines[:max_lines]:
        c.drawString(x, y, line)
        y -= leading
    return y


def draw_header(c, title, subtitle, bg, logo_paths, page_type="blue", accent=None, text_color="#FFFFFF", run_env_text=None):
    W, H = landscape(letter)
    c.setFillColor(colors.HexColor(bg))
    c.rect(0, H - 84, W, 84, fill=1, stroke=0)
    # small accent ribbon
    accent = accent or ("#BA0C2F" if page_type == "blue" else "#002D72")
    c.setFillColor(colors.HexColor(accent))
    c.rect(0, H - 92, W, 8, fill=1, stroke=0)
    # Larger LIDOM logo for stronger page branding.
    safe_draw_image(c, logo_paths.get("lidom"), 22, H - 82, 72, 72)
    c.setFillColor(colors.HexColor(text_color))
    c.setFont("Helvetica-Bold", 22)
    c.drawString(108, H - 42, title)
    c.setFont("Helvetica", 9)
    c.drawString(110, H - 63, subtitle)
    if run_env_text:
        # Small context badge: gives the reader the league scoring environment.
        badge_w = 92
        badge_h = 20
        bx = W - badge_w - 28
        by = H - 61
        c.setStrokeColor(colors.HexColor(text_color))
        c.setLineWidth(0.8)
        c.roundRect(bx, by, badge_w, badge_h, 8, fill=0, stroke=1)
        c.setFont("Helvetica-Bold", 8.5)
        c.drawCentredString(bx + badge_w / 2, by + 6, run_env_text)


def draw_footer(c, page_num, logo_paths, bg="#001F4E", selected_team="Leones del Escogido"):
    W, H = landscape(letter)
    c.setFillColor(colors.HexColor(bg))
    c.rect(0, 0, W, 28, fill=1, stroke=0)
    safe_draw_image(c, team_logo_path_for(logo_paths, selected_team) or logo_paths.get("lidom"), 20, 2, 66, 24)
    c.setFillColor(colors.white)
    c.setFont("Helvetica-Bold", 7.5)
    c.drawCentredString(W / 2, 10, "PASIÓN   ★   TRADICIÓN   ★   GLORIA")
    c.drawRightString(W - 24, 10, f"Page {page_num}")


