def rank_position(df, stat, team="Leones del Escogido", ascending=False):
    if df.empty or stat not in df.columns:
        return None, None
    show = df[["fullName", stat]].copy().sort_values(stat, ascending=ascending, na_position="last").reset_index(drop=True)
    mask = show["fullName"].apply(normalize_team_name).eq(normalize_team_name(team))
    if not mask.any():
        return None, None
    idx = int(show.index[mask][0])
    return idx + 1, show.loc[idx, stat]


def safe_fmt(stat, val):
    return format_value(stat, val) if val is not None and not pd.isna(val) else "—"


def league_average_value(df: pd.DataFrame, stat: str):
    """Return a league-average value for the stat shown in a PDF table.

    Counts are shown as average per team. Rate stats are weighted when the
    component columns exist; otherwise they fall back to the mean of team rates.
    """
    if df is None or df.empty or stat not in df.columns:
        return None
    data = df.copy()

    def _safe_div(num, den):
        try:
            den = float(den)
            return float(num) / den if den else None
        except Exception:
            return None

    # True/weighted league rates when the raw components are available.
    if stat == "BA" and {"Hits", "AB"}.issubset(data.columns):
        return _safe_div(data["Hits"].sum(), data["AB"].sum())
    if stat == "OBP" and {"ReachedBase", "PA"}.issubset(data.columns):
        return _safe_div(data["ReachedBase"].sum(), data["PA"].sum())
    if stat == "SLG" and {"TB", "PA"}.issubset(data.columns):
        return _safe_div(data["TB"].sum(), data["PA"].sum())
    if stat == "OPS":
        obp = league_average_value(data, "OBP")
        slg = league_average_value(data, "SLG")
        if obp is not None and slg is not None:
            return obp + slg
    if stat == "BB%" and {"BB", "PA"}.issubset(data.columns):
        return _safe_div(data["BB"].sum(), data["PA"].sum())
    if stat == "K%" and {"K", "PA"}.issubset(data.columns):
        return _safe_div(data["K"].sum(), data["PA"].sum())
    if stat == "SB%" and {"SB", "SBA"}.issubset(data.columns):
        return _safe_div(data["SB"].sum(), data["SBA"].sum())

    vals = pd.to_numeric(data[stat], errors="coerce").dropna()
    if vals.empty:
        return None
    return float(vals.mean())


def format_league_average(stat: str, val):
    if val is None or pd.isna(val):
        return "—"
    if stat in RATE_STATS or stat in {"ERA", "FIP", "WHIP"}:
        return format_value(stat, val)
    return f"{float(val):.1f}"


def calculate_run_environment_from_raw(team_frames):
    """Estimate league R/G if uploaded CSVs include run or score columns.

    The app supports both play-level run columns (summed by team-game) and
    cumulative team-score columns (max by team-game). If no recognizable column
    exists, the PDF header will show R/G: — instead of guessing.
    """
    if not team_frames:
        return None

    play_run_candidates = [
        "runsScored", "runs_scored", "runsOnPlay", "runs_on_play", "runs_play",
        "RunsScored", "Runs On Play", "runsscored",
    ]
    score_candidates = [
        # Common final/current team run columns from the uploaded baseball CSVs.
        # Prefer totalRuns/currentRuns because those are team-side values and allow
        # a real R/G instead of leaving the header blank.
        "totalRuns", "currentRuns", "teamRuns", "TeamRuns",
        "teamScore", "battingTeamScore", "postBattingTeamScore", "offenseScore",
        "batting_team_score", "TeamScore", "Runs", "runs", "R",
    ]

    team_game_runs = []
    for file_name, df in team_frames:
        if df is None or df.empty or "fullName" not in df.columns:
            continue
        tmp = df.copy()
        tmp["fullName"] = tmp["fullName"].apply(normalize_team_name)
        game_col = "gameId" if "gameId" in tmp.columns else "game_date" if "game_date" in tmp.columns else None
        if game_col is None:
            date_col = "date" if "date" in tmp.columns else "gameDate" if "gameDate" in tmp.columns else None
            if date_col:
                tmp["_game_key"] = pd.to_datetime(tmp[date_col], errors="coerce").dt.date.astype(str)
                game_col = "_game_key"
            else:
                tmp["_game_key"] = file_name
                game_col = "_game_key"

        play_col = next((c for c in play_run_candidates if c in tmp.columns), None)
        if play_col:
            tmp[play_col] = pd.to_numeric(tmp[play_col], errors="coerce").fillna(0)
            g = tmp.groupby(["fullName", game_col])[play_col].sum().reset_index(name="runs")
            team_game_runs.extend(g["runs"].dropna().tolist())
            continue

        score_col = next((c for c in score_candidates if c in tmp.columns), None)
        if score_col:
            tmp[score_col] = pd.to_numeric(tmp[score_col], errors="coerce")
            g = tmp.groupby(["fullName", game_col])[score_col].max().reset_index(name="runs")
            team_game_runs.extend(g["runs"].dropna().tolist())

    vals = [float(v) for v in team_game_runs if pd.notna(v)]
    if not vals:
        return None
    # Guardrail: avoid obvious bad cumulative season totals being treated as game scores.
    vals = [v for v in vals if 0 <= v <= 40]
    if not vals:
        return None
    return float(np.mean(vals))


def format_run_environment(run_env):
    return f"R/G: {run_env:.2f}" if run_env is not None and not pd.isna(run_env) else "R/G: —"


def team_voice_key(team: str) -> str:
    team = normalize_team_name(team)
    mapping = {
        "Leones del Escogido": "escogido",
        "Aguilas Cibaenas": "aguilas",
        "Águilas Cibaeñas": "aguilas",
        "Tigres del Licey": "licey",
        "Estrellas Orientales": "estrellas",
        "Gigantes del Cibao": "gigantes",
        "Toros del Este": "toros",
    }
    return mapping.get(team, "generic")


def ordinal_text(rank):
    return f"#{rank}" if rank is not None else "sin ranking"


def metric_phrase(stat, rank, value):
    return f"{ordinal_text(rank)} ({safe_fmt(stat, value)})"


def make_team_summary(section, hitting, baserunning, selected_team="Leones del Escogido"):
    """POV-aware summaries with team-specific wording.

    The goal is for each club report to sound different, not like the same
    paragraph with a team name swapped in.
    """
    team_name = normalize_team_name(selected_team)
    team_short = team_short_name(team_name)
    voice = team_voice_key(team_name)

    if section == "hitting":
        ops_r, ops_v = rank_position(hitting, "OPS", team=team_name, ascending=False)
        obp_r, obp_v = rank_position(hitting, "OBP", team=team_name, ascending=False)
        slg_r, slg_v = rank_position(hitting, "SLG", team=team_name, ascending=False)
        ba_r, ba_v = rank_position(hitting, "BA", team=team_name, ascending=False)
        bb_r, bb_v = rank_position(hitting, "BB%", team=team_name, ascending=False)
        k_r, k_v = rank_position(hitting, "K%", team=team_name, ascending=True)
        hits_r, hits_v = rank_position(hitting, "Hits", team=team_name, ascending=False)
        hr_r, hr_v = rank_position(hitting, "Homerun", team=team_name, ascending=False)

        if voice == "escogido":
            return (
                f"La ofensiva de {team_short} se entiende mejor desde la disciplina y la creación de tráfico. OBP {metric_phrase('OBP', obp_r, obp_v)} "
                f"y BB% {metric_phrase('BB%', bb_r, bb_v)} muestran un club que alarga turnos y obliga al pitcheo rival a trabajar. "
                f"El área de crecimiento está en convertir ese tráfico en daño: OPS {metric_phrase('OPS', ops_r, ops_v)}, SLG {metric_phrase('SLG', slg_r, slg_v)} "
                f"y HR {metric_phrase('Homerun', hr_r, hr_v)} dejan claro dónde puede venir el próximo salto. Con BA {metric_phrase('BA', ba_r, ba_v)} "
                f"y K% {metric_phrase('K%', k_r, k_v)}, la prioridad es mantener la zona sin dejar pasar swings de impacto en conteos favorables."
            )
        if voice == "aguilas":
            return (
                f"Aguilas presenta el perfil ofensivo más completo del grupo: combina contacto, embasamiento y daño sin depender de una sola vía. "
                f"El equipo lidera o se mantiene arriba en OPS {metric_phrase('OPS', ops_r, ops_v)}, OBP {metric_phrase('OBP', obp_r, obp_v)}, "
                f"SLG {metric_phrase('SLG', slg_r, slg_v)} y BA {metric_phrase('BA', ba_r, ba_v)}, lo que habla de una ofensiva estable tanto en proceso como en resultado. "
                f"El volumen de hits {metric_phrase('Hits', hits_r, hits_v)} y HR {metric_phrase('Homerun', hr_r, hr_v)} confirma que el ataque no solo llega a base, también empuja la pelota. "
                f"El reto será sostener ese estándar cuando los rivales ajusten el plan de pitcheo."
            )
        if voice == "licey":
            return (
                f"La lectura ofensiva de Licey apunta más a reconstrucción de ritmo que a dominio acumulado. OPS {metric_phrase('OPS', ops_r, ops_v)}, "
                f"SLG {metric_phrase('SLG', slg_r, slg_v)} y BA {metric_phrase('BA', ba_r, ba_v)} sugieren que el club necesita encadenar mejores contactos para cambiar innings. "
                f"Hay señales de competencia en la zona con BB% {metric_phrase('BB%', bb_r, bb_v)}, pero OBP {metric_phrase('OBP', obp_r, obp_v)} indica que todavía falta convertir turnos largos en tráfico constante. "
                f"El enfoque ofensivo debe ser simplificar el plan: más contacto temprano con intención, mejores decisiones con hombres en base y menos turnos vacíos."
            )
        if voice == "estrellas":
            return (
                f"Estrellas muestra una ofensiva de volumen, con una base importante en hits {metric_phrase('Hits', hits_r, hits_v)} y producción sostenida por contacto. "
                f"OPS {metric_phrase('OPS', ops_r, ops_v)}, OBP {metric_phrase('OBP', obp_r, obp_v)} y BA {metric_phrase('BA', ba_r, ba_v)} reflejan un equipo capaz de fabricar rallies sin depender exclusivamente del cuadrangular. "
                f"El punto que puede separar al club es aumentar la calidad del contacto: SLG {metric_phrase('SLG', slg_r, slg_v)} y HR {metric_phrase('Homerun', hr_r, hr_v)} marcan cuánto daño acompaña al volumen. "
                f"Si el contacto se transforma en más extrabases, el lineup gana otra dimensión."
            )
        if voice == "gigantes":
            return (
                f"Gigantes tiene una ofensiva que necesita reducir el margen de error. OPS {metric_phrase('OPS', ops_r, ops_v)}, OBP {metric_phrase('OBP', obp_r, obp_v)} "
                f"y SLG {metric_phrase('SLG', slg_r, slg_v)} describen un ataque que todavía busca continuidad entre turnos de calidad y producción real. "
                f"El total de hits {metric_phrase('Hits', hits_r, hits_v)} y HR {metric_phrase('Homerun', hr_r, hr_v)} muestra momentos de daño, pero la clave será sostener presión por más innings. "
                f"Para subir en la liga, el plan debe concentrarse en llegar a base con más frecuencia y proteger mejor los turnos de alto valor."
            )
        if voice == "toros":
            return (
                f"Toros tiene un perfil ofensivo con fuerza clara en el daño. HR {metric_phrase('Homerun', hr_r, hr_v)} y SLG {metric_phrase('SLG', slg_r, slg_v)} "
                f"apuntan a un equipo que puede cambiar el juego con swings grandes. La pregunta es si ese poder puede ir acompañado de más tráfico: OBP {metric_phrase('OBP', obp_r, obp_v)} "
                f"y BB% {metric_phrase('BB%', bb_r, bb_v)} ayudan a medir cuántas oportunidades extra se crean antes del contacto fuerte. "
                f"Si el club combina disciplina con su capacidad de impacto, el techo ofensivo sube bastante."
            )

        return (
            f"La ofensiva de {team_short} combina OPS {metric_phrase('OPS', ops_r, ops_v)}, OBP {metric_phrase('OBP', obp_r, obp_v)} y SLG {metric_phrase('SLG', slg_r, slg_v)}. "
            f"El enfoque debe ser crear más tráfico, proteger el K% {metric_phrase('K%', k_r, k_v)} y convertir mejores swings en daño sostenible."
        )

    if section == "baserunning":
        sb_r, sb_v = rank_position(baserunning, "SB", team=team_name, ascending=False)
        cs_r, cs_v = rank_position(baserunning, "CS", team=team_name, ascending=True)
        rate_r, rate_v = rank_position(baserunning, "SB%", team=team_name, ascending=False)
        sba_r, sba_v = rank_position(baserunning, "SBA", team=team_name, ascending=False)

        if voice == "escogido":
            return (
                f"El corrido de bases de Escogido funciona como presión constante. SBA {metric_phrase('SBA', sba_r, sba_v)} y SB {metric_phrase('SB', sb_r, sb_v)} "
                f"muestran un equipo dispuesto a forzar decisiones al rival. El ajuste está en el valor neto: SB% {metric_phrase('SB%', rate_r, rate_v)} y CS {metric_phrase('CS', cs_r, cs_v)} "
                f"dicen si esa presión está produciendo ventajas o entregando outs. No se trata de correr menos, sino de escoger mejores ventanas para correr."
            )
        if voice == "aguilas":
            return (
                f"Aguilas corre con eficiencia más que con volumen descontrolado. SB% {metric_phrase('SB%', rate_r, rate_v)} y CS {metric_phrase('CS', cs_r, cs_v)} "
                f"sugieren una toma de decisiones limpia, con intentos que suelen justificar el riesgo. SB {metric_phrase('SB', sb_r, sb_v)} y SBA {metric_phrase('SBA', sba_r, sba_v)} "
                f"dejan espacio para ser más agresivos sin romper la identidad. La pregunta es cuándo añadir volumen sin sacrificar precisión."
            )
        if voice == "licey":
            return (
                f"Para Licey, el juego de piernas debe convertirse en una manera de compensar momentos de baja producción ofensiva. SB {metric_phrase('SB', sb_r, sb_v)} y SBA {metric_phrase('SBA', sba_r, sba_v)} "
                f"muestran actividad, pero SB% {metric_phrase('SB%', rate_r, rate_v)} y CS {metric_phrase('CS', cs_r, cs_v)} obligan a revisar selección de lanzadores, conteos y game state. "
                f"El objetivo es que cada intento ayude a fabricar carreras, no que simplemente aumente el volumen de movimiento."
            )
        if voice == "estrellas":
            return (
                f"Estrellas necesita que el corrido de bases complemente su ofensiva de contacto. SB {metric_phrase('SB', sb_r, sb_v)} y SBA {metric_phrase('SBA', sba_r, sba_v)} "
                f"indican cuánta presión se agrega después de llegar a base. La eficiencia SB% {metric_phrase('SB%', rate_r, rate_v)} y el control de CS {metric_phrase('CS', cs_r, cs_v)} "
                f"serán claves para que los rallies no se apaguen. La prioridad es elegir intentos que alarguen innings y mantengan tráfico."
            )
        if voice == "gigantes":
            return (
                f"Gigantes tiene un componente físico en bases que puede cambiar el ritmo del juego. SB {metric_phrase('SB', sb_r, sb_v)} y SBA {metric_phrase('SBA', sba_r, sba_v)} "
                f"reflejan disposición para atacar. El punto fino es convertir esa agresividad en eficiencia: SB% {metric_phrase('SB%', rate_r, rate_v)} frente a CS {metric_phrase('CS', cs_r, cs_v)}. "
                f"Si el club limpia sus lecturas, el corrido puede pasar de recurso ocasional a ventaja competitiva."
            )
        if voice == "toros":
            return (
                f"Toros usa las bases como extensión de su ofensiva de impacto. SB {metric_phrase('SB', sb_r, sb_v)} y SBA {metric_phrase('SBA', sba_r, sba_v)} "
                f"muestran una mentalidad de atacar al rival incluso sin batazo grande. La eficiencia SB% {metric_phrase('SB%', rate_r, rate_v)} y CS {metric_phrase('CS', cs_r, cs_v)} "
                f"determinan si esa agresividad crea innings grandes o corta oportunidades. El balance ideal es poder más presión, sin regalar outs."
            )

        return (
            f"El corrido de bases de {team_short} muestra SB {metric_phrase('SB', sb_r, sb_v)}, SBA {metric_phrase('SBA', sba_r, sba_v)} y SB% {metric_phrase('SB%', rate_r, rate_v)}. "
            f"La prioridad es maximizar valor sin aumentar outs evitables."
        )

    # Rolling summaries: different tone by club.
    if voice == "escogido":
        return (
            f"La tendencia de Escogido debe leerse como una búsqueda de estabilidad: sostener disciplina, crear tráfico y decidir mejor cuándo presionar en bases. "
            f"Las curvas permiten separar un buen tramo de una mejora real. Si el OBP se mantiene y el equipo convierte más corredores en daño, el perfil gana peligro sin cambiar su identidad."
        )
    if voice == "aguilas":
        return (
            f"En Aguilas, las tendencias sirven para vigilar si el dominio acumulado se mantiene o empieza a normalizarse. El valor está en sostener la separación en métricas de calidad, no solo en liderar el cierre del reporte. "
            f"Mientras el contacto, el OBP y la eficiencia en bases sigan viajando juntos, el equipo conserva una ventaja estructural."
        )
    if voice == "licey":
        return (
            f"Para Licey, la página de tendencias es una herramienta de alerta temprana. Más que celebrar el acumulado, ayuda a detectar dónde empieza una recuperación: OBP, contacto, daño o eficiencia en bases. "
            f"El objetivo del próximo tramo es cambiar la pendiente de las curvas antes de que el ranking final cierre el margen de reacción."
        )
    if voice == "estrellas":
        return (
            f"Las tendencias de Estrellas deben enfocarse en continuidad. Cuando el volumen de hits se sostiene, el siguiente indicador importante es si ese tráfico se transforma en slugging y carreras. "
            f"La lectura semanal debe buscar señales de impacto: más extrabases, mejor eficiencia en bases y menos innings donde el contacto no produce avance real."
        )
    if voice == "gigantes":
        return (
            f"En Gigantes, la página de rolling funciona como mapa de consistencia. El ranking final puede esconder tramos buenos y malos; las curvas enseñan cuándo el equipo compitió al nivel de la liga y cuándo perdió terreno. "
            f"El reto es reducir caídas largas y construir rachas donde ofensiva, pitcheo y defensa se alineen al mismo tiempo."
        )
    if voice == "toros":
        return (
            f"Para Toros, las curvas ayudan a medir si el daño ofensivo llega en picos aislados o en una tendencia sostenible. El poder cambia juegos, pero la estabilidad aparece cuando OBP, SLG y presión en bases crecen juntos. "
            f"La clave es evitar que el perfil dependa solo del extrabase y añadir más tráfico antes de los swings grandes."
        )

    return (
        f"La página de tendencias muestra cómo {team_short} llegó a su posición actual. El objetivo es sostener fortalezas, corregir caídas temprano y convertir mejores tramos en ventaja acumulada."
    )


# Backward-compatible name in case older calls remain.
def make_escogido_summary(section, hitting, baserunning):
    return make_team_summary(section, hitting, baserunning, "Leones del Escogido")


def make_team_pitching_summary(pitching, selected_team="Leones del Escogido"):
    team_name = normalize_team_name(selected_team)
    team_short = team_short_name(team_name)
    voice = team_voice_key(team_name)
    if pitching is None or pitching.empty:
        return f"Carga el archivo LIDOM Draft para generar el resumen de pitcheo de {team_short}."
    era_r, era_v = rank_position(pitching, "ERA", team=team_name, ascending=True)
    fip_r, fip_v = rank_position(pitching, "FIP", team=team_name, ascending=True)
    whip_r, whip_v = rank_position(pitching, "WHIP", team=team_name, ascending=True)
    k_r, k_v = rank_position(pitching, "K%", team=team_name, ascending=False)
    bb_r, bb_v = rank_position(pitching, "BB%", team=team_name, ascending=True)
    hr_r, hr_v = rank_position(pitching, "HR%", team=team_name, ascending=True)
    baa_r, baa_v = rank_position(pitching, "BAA", team=team_name, ascending=True)

    if voice == "aguilas":
        return (
            f"El staff de Aguilas tiene una base de dominio real: K% {metric_phrase('K%', k_r, k_v)} y ERA {metric_phrase('ERA', era_r, era_v)} le dan al club capacidad para controlar innings. "
            f"El área que puede elevar el techo está en comando fino: BB% {metric_phrase('BB%', bb_r, bb_v)} y HR% {metric_phrase('HR%', hr_r, hr_v)} marcan cuánto daño gratis se concede. "
            f"Si el ponche se mantiene y los boletos bajan, FIP {metric_phrase('FIP', fip_r, fip_v)} debería acercarse al resultado del ERA."
        )
    if voice == "licey":
        return (
            f"El pitcheo de Licey se sostiene por prevención de carreras y control de tráfico. ERA {metric_phrase('ERA', era_r, era_v)} y WHIP {metric_phrase('WHIP', whip_r, whip_v)} "
            f"describen un staff que limita rallies aun cuando el contacto aparece. FIP {metric_phrase('FIP', fip_r, fip_v)} ayuda a medir si ese rendimiento es sostenible. "
            f"La tarea es mantener BB% {metric_phrase('BB%', bb_r, bb_v)} bajo control y encontrar más finalización de turnos con K% {metric_phrase('K%', k_r, k_v)}."
        )
    if voice == "toros":
        return (
            f"El pitcheo de Toros debe evaluarse por daño permitido y ejecución con hombres en base. ERA {metric_phrase('ERA', era_r, era_v)} y FIP {metric_phrase('FIP', fip_r, fip_v)} "
            f"dan una idea del rendimiento real y esperado. WHIP {metric_phrase('WHIP', whip_r, whip_v)} muestra cuánto tráfico se permite, mientras HR% {metric_phrase('HR%', hr_r, hr_v)} "
            f"define si los errores se convierten en daño grande. El foco es atacar temprano y cerrar turnos sin extender innings."
        )
    if voice == "estrellas":
        return (
            f"El staff de Estrellas tiene una lectura interesante desde FIP {metric_phrase('FIP', fip_r, fip_v)} y HR% {metric_phrase('HR%', hr_r, hr_v)}: los indicadores de proceso apuntan a capacidad de limitar daño fuerte. "
            f"La distancia con ERA {metric_phrase('ERA', era_r, era_v)} y WHIP {metric_phrase('WHIP', whip_r, whip_v)} señala dónde el tráfico todavía pesa. "
            f"El próximo paso es transformar buen proceso en innings más limpios y menos situaciones de estrés."
        )
    if voice == "gigantes":
        return (
            f"Gigantes tiene que mirar el pitcheo desde control de contacto y reducción de daño. BAA {metric_phrase('BAA', baa_r, baa_v)} y WHIP {metric_phrase('WHIP', whip_r, whip_v)} "
            f"muestran cuánto trabajo enfrenta la defensa. K% {metric_phrase('K%', k_r, k_v)} da una vía para salir de problemas, pero BB% {metric_phrase('BB%', bb_r, bb_v)} y HR% {metric_phrase('HR%', hr_r, hr_v)} "
            f"determinan si esos problemas se convierten en carreras. La prioridad es recortar tráfico gratis."
        )
    if voice == "escogido":
        return (
            f"El pitcheo de Escogido vive entre comando y margen. BB% {metric_phrase('BB%', bb_r, bb_v)} muestra capacidad para evitar regalos, pero ERA {metric_phrase('ERA', era_r, era_v)}, "
            f"WHIP {metric_phrase('WHIP', whip_r, whip_v)} y BAA {metric_phrase('BAA', baa_r, baa_v)} indican que todavía hay demasiado tráfico útil para el rival. "
            f"El salto vendrá de subir K% {metric_phrase('K%', k_r, k_v)} y limitar HR% {metric_phrase('HR%', hr_r, hr_v)} sin perder la ventaja de control."
        )

    return (
        f"El perfil de pitcheo de {team_short} combina ERA {metric_phrase('ERA', era_r, era_v)}, FIP {metric_phrase('FIP', fip_r, fip_v)} y WHIP {metric_phrase('WHIP', whip_r, whip_v)}. "
        f"El foco debe ser controlar tráfico, generar más outs de calidad y limitar daño largo."
    )


def make_escogido_pitching_summary(pitching):
    return make_team_pitching_summary(pitching, "Leones del Escogido")


def make_team_defense_summary(defense, selected_team="Leones del Escogido"):
    team_name = normalize_team_name(selected_team)
    team_short = team_short_name(team_name)
    voice = team_voice_key(team_name)
    if defense is None or defense.empty:
        return f"Carga los archivos de defensa para generar el resumen defensivo de {team_short}."
    cs_r, cs_v = rank_position(defense, "CS%", team=team_name, ascending=False)
    ife_r, ife_v = rank_position(defense, "IFErr", team=team_name, ascending=True)
    iff_r, iff_v = rank_position(defense, "IFFld%", team=team_name, ascending=False)
    ofe_r, ofe_v = rank_position(defense, "OFErr", team=team_name, ascending=True)
    off_r, off_v = rank_position(defense, "OFFld%", team=team_name, ascending=False)

    if voice == "aguilas":
        return (
            f"La defensa de Aguilas tiene una división clara: el outfield aporta seguridad de alto nivel con OFErr {metric_phrase('OFErr', ofe_r, ofe_v)} y OFFld% {metric_phrase('OFFld%', off_r, off_v)}, "
            f"mientras el infield necesita mayor estabilidad con IFErr {metric_phrase('IFErr', ife_r, ife_v)} e IFFld% {metric_phrase('IFFld%', iff_r, iff_v)}. "
            f"El catching, CS% {metric_phrase('CS%', cs_r, cs_v)}, será importante para equilibrar el juego de correr rival. La meta es que la defensa completa acompañe el nivel del outfield."
        )
    if voice == "licey":
        return (
            f"Licey defiende con una base sólida en los jardines: OFErr {metric_phrase('OFErr', ofe_r, ofe_v)} y OFFld% {metric_phrase('OFFld%', off_r, off_v)} ayudan a cortar daño extra. "
            f"El catching, CS% {metric_phrase('CS%', cs_r, cs_v)}, suma control al running game. En el infield, IFErr {metric_phrase('IFErr', ife_r, ife_v)} e IFFld% {metric_phrase('IFFld%', iff_r, iff_v)} "
            f"marcan el área donde la consistencia puede mejorar la prevención de carreras."
        )
    if voice == "estrellas":
        return (
            f"La defensa de Estrellas se apoya en convertir outs rutinarios y no regalar entradas extendidas. IFErr {metric_phrase('IFErr', ife_r, ife_v)} e IFFld% {metric_phrase('IFFld%', iff_r, iff_v)} "
            f"muestran la estabilidad del cuadro, mientras OFErr {metric_phrase('OFErr', ofe_r, ofe_v)} y OFFld% {metric_phrase('OFFld%', off_r, off_v)} miden cuánto se protege el espacio grande. "
            f"CS% {metric_phrase('CS%', cs_r, cs_v)} completa la lectura del apoyo al pitcheo."
        )
    if voice == "gigantes":
        return (
            f"Gigantes destaca primero por el control del juego de correr: CS% {metric_phrase('CS%', cs_r, cs_v)} puede cambiar la manera en que los rivales toman riesgos. "
            f"La siguiente capa está en asegurar la pelota en el infield y outfield: IFErr {metric_phrase('IFErr', ife_r, ife_v)}, IFFld% {metric_phrase('IFFld%', iff_r, iff_v)}, "
            f"OFErr {metric_phrase('OFErr', ofe_r, ofe_v)} y OFFld% {metric_phrase('OFFld%', off_r, off_v)}. El objetivo es convertir esa fortaleza de batería en defensa completa."
        )
    if voice == "toros":
        return (
            f"La defensa de Toros debe verse desde ejecución y limpieza. IFErr {metric_phrase('IFErr', ife_r, ife_v)} e IFFld% {metric_phrase('IFFld%', iff_r, iff_v)} dicen cuánto se asegura el contacto terrestre; "
            f"OFErr {metric_phrase('OFErr', ofe_r, ofe_v)} y OFFld% {metric_phrase('OFFld%', off_r, off_v)} evalúan el control del espacio. "
            f"Con CS% {metric_phrase('CS%', cs_r, cs_v)}, el staff puede saber si la defensa está ayudando a controlar innings o solo evitando errores visibles."
        )
    if voice == "escogido":
        return (
            f"La defensa de Escogido se sostiene desde el infield. IFErr {metric_phrase('IFErr', ife_r, ife_v)} e IFFld% {metric_phrase('IFFld%', iff_r, iff_v)} hablan de una base confiable para convertir contacto en outs. "
            f"El catching, CS% {metric_phrase('CS%', cs_r, cs_v)}, ofrece una lectura del control del running game. El punto de mejora aparece en el outfield con OFErr {metric_phrase('OFErr', ofe_r, ofe_v)} "
            f"y OFFld% {metric_phrase('OFFld%', off_r, off_v)}. El objetivo es que la seguridad del cuadro se extienda a todo el campo."
        )

    return (
        f"La defensa de {team_short} combina CS% {metric_phrase('CS%', cs_r, cs_v)}, IFErr {metric_phrase('IFErr', ife_r, ife_v)} e OFFld% {metric_phrase('OFFld%', off_r, off_v)}. "
        f"El enfoque debe ser sostener outs rutinarios y evitar innings extendidos."
    )


def make_escogido_defense_summary(defense):
    return make_team_defense_summary(defense, "Leones del Escogido")

def draw_summary_box(c, title, body, x, y, w, h, logo_paths, selected_team="Leones del Escogido", border_color=None, title_color=None):
    theme = get_team_theme(selected_team)
    border_color = border_color or theme["primary"]
    title_color = title_color or theme["highlight_text"]
    c.setStrokeColor(colors.HexColor(border_color))
    c.setLineWidth(0.9)
    c.setFillColor(colors.white)
    c.roundRect(x, y, w, h, 7, fill=1, stroke=1)

    # Summary logo/title spacing fix:
    # Keep the team logo in a fixed-width zone so wide logos never collide with the title.
    logo_path = team_logo_path_for(logo_paths, selected_team) or logo_paths.get("lidom")
    logo_w = 34
    logo_h = 20
    logo_x = x + 9
    logo_y = y + h - 31
    safe_draw_image(c, logo_path, logo_x, logo_y, logo_w, logo_h)

    c.setFillColor(colors.HexColor(title_color))
    title_font = 7.4 if w < 230 else 8.0
    c.setFont("Helvetica-Bold", title_font)
    title_x = x + 56
    c.drawString(title_x, y + h - 19, title.upper())

    # Detailed but still compact: body starts below both logo and title.
    draw_wrapped_text(c, body, x + 12, y + h - 43, w - 24, size=6.1, leading=7.4, max_lines=11)


def draw_stat_table(c, df, stat, x, y, w, h, logo_paths, theme="#002D72", ascending=False, icon=None, icon_image=None, selected_team="Leones del Escogido", highlight_bg=None, highlight_text=None, table_text="#FFFFFF"):
    title, subtitle = STAT_LABELS.get(stat, (stat, stat))
    # Clean card with a little breathing room
    c.setFillColor(colors.white)
    c.setStrokeColor(colors.HexColor("#D7DEE9"))
    c.setLineWidth(0.55)
    c.roundRect(x, y, w, h, 6, fill=1, stroke=1)

    header_h = 32
    # Shorter label so it fits cleanly in tight table headers.
    avg_text = f"{title} League Avg: {format_league_average(stat, league_average_value(df, stat))}"
    c.setFillColor(colors.HexColor(theme))
    c.roundRect(x, y + h - header_h, w, header_h, 6, fill=1, stroke=0)
    c.rect(x, y + h - header_h, w, header_h - 5, fill=1, stroke=0)

    if icon_image:
        # White badge keeps the runner visible on every team-color header.
        c.setFillColor(colors.white)
        c.circle(x + 19, y + h - 16, 12, fill=1, stroke=0)
        safe_draw_image(c, icon_image, x + 8, y + h - 27, 22, 22)
        title_x = x + 40
        c.setFillColor(colors.HexColor(table_text))
        c.setFont("Helvetica-Bold", 10.5)
        c.drawString(title_x, y + h - 11, title)
        c.setFont("Helvetica", 5.8)
        c.drawString(title_x, y + h - 21, subtitle)
        c.setFont("Helvetica-Bold", 5.8)
        c.drawString(title_x, y + h - 29, avg_text)
    elif icon:
        c.setFillColor(colors.HexColor(table_text))
        c.circle(x + 19, y + h - 16, 11, fill=0, stroke=1)
        c.setFont("Helvetica-Bold", 11)
        c.drawCentredString(x + 19, y + h - 20, icon)
        title_x = x + 38
        c.setFillColor(colors.HexColor(table_text))
        c.setFont("Helvetica-Bold", 10.5)
        c.drawString(title_x, y + h - 11, title)
        c.setFont("Helvetica", 5.8)
        c.drawString(title_x, y + h - 21, subtitle)
        c.setFont("Helvetica-Bold", 5.8)
        c.drawString(title_x, y + h - 29, avg_text)
    else:
        c.setFillColor(colors.HexColor(table_text))
        c.setFont("Helvetica-Bold", 10.5)
        c.drawCentredString(x + w / 2, y + h - 11, title)
        c.setFont("Helvetica", 5.8)
        c.drawCentredString(x + w / 2, y + h - 21, subtitle)
        c.setFont("Helvetica-Bold", 5.8)
        c.drawCentredString(x + w / 2, y + h - 29, avg_text)

    # Column header
    ch_h = 15
    ch_y = y + h - header_h - ch_h
    c.setFillColor(colors.HexColor(theme))
    c.rect(x, ch_y, w, ch_h, fill=1, stroke=0)
    c.setFillColor(colors.HexColor(table_text))
    c.setFont("Helvetica-Bold", 6.2)
    c.drawCentredString(x + 17, ch_y + 5, "RANK")
    c.drawCentredString(x + w * 0.52, ch_y + 5, "TEAM")
    c.drawCentredString(x + w - 20, ch_y + 5, stat.upper())

    table = pdf_rank_table(df, stat, ascending=ascending)
    row_h = (h - header_h - ch_h) / 6.0
    top = ch_y
    for i in range(6):
        ry = top - (i + 1) * row_h
        if i < len(table):
            r = table.iloc[i]
            team = str(r["Team"])
            is_esc = normalize_team_name(team) == normalize_team_name(selected_team)
        else:
            is_esc = False
        if is_esc:
            c.setFillColor(colors.HexColor(highlight_bg or team_highlight_bg(selected_team)))
        else:
            c.setFillColor(colors.HexColor("#F6F8FB") if i % 2 else colors.white)
        c.rect(x, ry, w, row_h, fill=1, stroke=0)
        if i < len(table):
            r = table.iloc[i]
            team = str(r["Team"])
            val = str(r[stat])
            is_esc = normalize_team_name(team) == normalize_team_name(selected_team)
            color = (highlight_text or team_highlight_color(selected_team)) if is_esc else "#111111"
            font = "Helvetica-Bold" if is_esc else "Helvetica"
            c.setFillColor(colors.HexColor(color))
            c.setFont(font, 7.4)
            c.drawCentredString(x + 17, ry + row_h / 2 - 2.2, str(r["Rank"]))
            draw_team_logo(c, logo_paths, team, x + 39, ry + row_h / 2 - 6.5, 13, 13)
            c.drawString(x + 58, ry + row_h / 2 - 2.2, team[:30])
            c.drawRightString(x + w - 10, ry + row_h / 2 - 2.2, val)
        c.setStrokeColor(colors.HexColor("#E3E8F0"))
        c.setLineWidth(0.25)
        c.line(x, ry, x + w, ry)
    c.setStrokeColor(colors.HexColor("#DDE5EF"))
    c.line(x + 35, y, x + 35, ch_y + ch_h)
    c.line(x + w - 45, y, x + w - 45, ch_y + ch_h)

def make_pdf_chart_image(rolling_df: pd.DataFrame, stat: str, title: str, width: float = 2.35, height: float = 1.42):
    """Create a PNG chart for the ReportLab PDF using matplotlib."""
    import matplotlib
    matplotlib.use("Agg")
    import matplotlib.pyplot as plt
    from matplotlib.ticker import FuncFormatter

    chart_df = rolling_df.dropna(subset=["game_date"]).copy()
    if chart_df.empty or stat not in chart_df.columns:
        return None

    chart_df["game_date"] = pd.to_datetime(chart_df["game_date"], errors="coerce")
    chart_df = chart_df.dropna(subset=["game_date"]).sort_values(["fullName", "game_date"])
    if chart_df.empty:
        return None

    fig, ax = plt.subplots(figsize=(width, height), dpi=180)
    for team, team_df in chart_df.groupby("fullName", sort=False):
        color = TEAM_COLORS.get(team, None)
        ax.plot(team_df["game_date"], team_df[stat], linewidth=1.55, label=team, color=color)

    ax.set_title(title, fontsize=8, fontweight="bold", pad=5)
    ax.set_xlabel("")
    ax.set_ylabel("")
    ax.grid(True, linewidth=0.3, alpha=0.28)
    ax.tick_params(axis="both", labelsize=5)
    fig.autofmt_xdate(rotation=0)
    if stat in {"BA", "OBP", "SLG", "OPS"}:
        ax.yaxis.set_major_formatter(FuncFormatter(lambda x, pos: f"{x:.3f}".replace("0.", ".")))
    elif stat in {"BB%", "K%", "SB%"}:
        ax.yaxis.set_major_formatter(FuncFormatter(lambda x, pos: f"{x:.0%}"))
    fig.tight_layout(pad=0.7)

    tmp = tempfile.NamedTemporaryFile(delete=False, suffix=".png")
    fig.savefig(tmp.name, bbox_inches="tight", facecolor="white")
    plt.close(fig)
    return tmp.name


def draw_chart_grid(c, rolling_hitting, rolling_baserunning, x, y, w, h, logo_paths, selected_team="Leones del Escogido"):
    """Cleaner rolling page: six key hitting trends plus three baserunning trends."""
    def chart(path_df, stat, title, cx, cy, cw, ch, width=2.45, height=1.25):
        path = make_pdf_chart_image(path_df, stat, title, width=width, height=height)
        if path:
            # Subtle chart card background
            c.setFillColor(colors.white)
            c.setStrokeColor(colors.HexColor("#E2E7EF"))
            c.roundRect(cx - 3, cy - 3, cw + 6, ch + 6, 5, fill=1, stroke=1)
            safe_draw_image(c, path, cx, cy, cw, ch)

    # Hitting key metrics: 3 columns x 2 rows, bigger and easier to read
    hit_stats = ["OPS", "OBP", "SLG", "BA", "BB%", "K%"]
    gx, gy, gw, gh = x, 292, w, 184
    gap_x, gap_y = 22, 18
    cols = 3
    cw = (gw - gap_x * (cols - 1)) / cols
    ch = (gh - gap_y) / 2
    for idx, stat in enumerate(hit_stats):
        row = idx // cols
        col = idx % cols
        cx = gx + col * (cw + gap_x)
        cy = gy + gh - (row + 1) * ch - row * gap_y
        chart(rolling_hitting, stat, stat, cx, cy, cw, ch, width=2.7, height=1.25)

    # Baserunning metrics: 3 wide charts in one row
    bx, by, bw, bh = x, 118, w * 0.68, 86
    gap_x = 18
    cw = (bw - gap_x * 2) / 3
    for idx, stat in enumerate(["SB", "CS", "SB%"]):
        cx = bx + idx * (cw + gap_x)
        chart(rolling_baserunning, stat, stat, cx, by, cw, bh, width=2.35, height=1.15)

    # Clean legend, one row when possible
    legend_y = 72
    lx = x + 4
    c.setFont("Helvetica", 6.0)
    legend_teams = list(pd.concat([rolling_hitting[["fullName"]], rolling_baserunning[["fullName"]]], ignore_index=True)["fullName"].dropna().drop_duplicates())[:6]
    for team in legend_teams:
        c.setStrokeColor(colors.HexColor(TEAM_COLORS.get(normalize_team_name(team), "#333333")))
        c.setLineWidth(2.0)
        c.line(lx, legend_y, lx + 15, legend_y)
        c.setFillColor(colors.HexColor("#222222"))
        label = team_short_name(team)
        c.drawString(lx + 19, legend_y - 2.2, label[:18])
        lx += 112

def to_pdf(hitting: pd.DataFrame, baserunning: pd.DataFrame, rolling_hitting: pd.DataFrame, rolling_baserunning: pd.DataFrame, pitching_sp: pd.DataFrame | None = None, pitching_rp: pd.DataFrame | None = None, defense: pd.DataFrame | None = None, logo_uploads: dict | None = None, selected_team: str = "Leones del Escogido", selected_league: str = "LIDOM", run_env_text: str | None = None) -> BytesIO:
    if not REPORTLAB_AVAILABLE:
        raise ImportError("ReportLab is not installed. Run: pip install reportlab")

    logo_paths = prepare_logo_paths(logo_uploads)
    league_cfg = LEAGUE_CONFIG.get(selected_league, LEAGUE_CONFIG["LIDOM"])
    league_display = league_cfg["display"]
    league_logo_key = league_cfg.get("logo_key", "lidom")
    active_league_logo = logo_paths.get(league_logo_key) or find_default_logo_path(league_logo_key)
    if active_league_logo:
        # draw_header uses logo_paths["lidom"] internally; replace it with the active league logo.
        logo_paths["lidom"] = active_league_logo
    output = BytesIO()
    c = canvas.Canvas(output, pagesize=landscape(letter))
    W, H = landscape(letter)
    date_txt = f"Generated {datetime.now().strftime('%b %d, %Y')}"
    report_theme = get_team_theme(selected_team)
    primary = report_theme["primary"]
    accent = report_theme["accent"]
    section_color = report_theme["section"]
    header_text = report_theme.get("header_text", "#FFFFFF")
    highlight_bg = report_theme["highlight_bg"]
    highlight_text = report_theme["highlight_text"]
    table_text = report_theme.get("table_text", "#FFFFFF")
    footer_bg = report_theme.get("footer_bg", primary)

    # Page 1 - Hitting category leaderboards, cleaner 3-column layout
    draw_header(c, f"{league_display} TEAM HITTING LEADERBOARDS", date_txt, primary, logo_paths, "blue", accent=accent, text_color=header_text, run_env_text=run_env_text)
    draw_section_title(c, "HITTING LEADERBOARDS BY CATEGORY   ★   ★", 24, H - 119, section_color)

    left = 24
    top = H - 140
    gap_x = 14
    gap_y = 8
    table_w = (W - 2 * left - 2 * gap_x) / 3
    table_h = 93
    hit_stats = ["OPS", "OBP", "SLG", "BA", "Hits", "Homerun", "Double", "Triple", "BB%", "K%", "Single"]
    for idx, stat in enumerate(hit_stats):
        row = idx // 3
        col = idx % 3
        x = left + col * (table_w + gap_x)
        y = top - (row + 1) * table_h - row * gap_y
        draw_stat_table(c, hitting, stat, x, y, table_w, table_h, logo_paths, theme=primary, ascending=(stat == "K%"), selected_team=selected_team, highlight_bg=highlight_bg, highlight_text=highlight_text, table_text=table_text)

    # Summary occupies the last open slot, but is taller so paragraph text fits cleanly.
    sx = left + 2 * (table_w + gap_x)
    sy = 44
    summary_h = 125
    draw_summary_box(
        c,
        f"{team_short_name(selected_team)} Hitting Summary",
        make_team_summary("hitting", hitting, baserunning, selected_team),
        sx,
        sy,
        table_w,
        summary_h,
        logo_paths,
        selected_team,
    )
    draw_footer(c, 1, logo_paths, footer_bg, selected_team)
    c.showPage()

    # Page 2 - Baserunning category leaderboards, bigger feature cards
    draw_header(c, f"{league_display} TEAM BASERUNNING LEADERBOARDS", date_txt, primary, logo_paths, "red", accent=accent, text_color=header_text, run_env_text=run_env_text)
    # Baserunning section icon: always prefer baserunning.png from the app folder/sidebar, with embedded fallback.
    safe_draw_image(c, logo_paths.get("baserunning"), 34, H - 132, 18, 18)
    draw_section_title(c, "BASERUNNING LEADERBOARDS BY CATEGORY   ★", 58, H - 119, section_color)

    br_left = 44
    br_top = H - 148
    br_w = (W - 2 * br_left - 2 * 24) / 3
    br_h = 188
    for idx, stat in enumerate(["SB", "CS", "SB%"]):
        x = br_left + idx * (br_w + 24)
        y = br_top - br_h
        draw_stat_table(
            c,
            baserunning,
            stat,
            x,
            y,
            br_w,
            br_h,
            logo_paths,
            theme=primary,
            ascending=(stat == "CS"),
            icon=None if stat in ["SB", "CS"] else ICON_SYMBOLS.get(stat),
            icon_image=logo_paths.get("baserunning") if stat in ["SB", "CS"] else None,
            selected_team=selected_team,
            highlight_bg=highlight_bg,
            highlight_text=highlight_text,
            table_text=table_text,
        )

    # Rank callout strip for selected report team
    sb_r, sb_v = rank_position(baserunning, "SB", team=selected_team, ascending=False)
    cs_r, cs_v = rank_position(baserunning, "CS", team=selected_team, ascending=True)
    sbp_r, sbp_v = rank_position(baserunning, "SB%", team=selected_team, ascending=False)
    c.setFillColor(colors.HexColor(highlight_bg))
    c.setStrokeColor(colors.HexColor(accent))
    c.roundRect(54, 198, W - 108, 46, 8, fill=1, stroke=1)
    safe_draw_image(c, team_logo_path_for(logo_paths, selected_team) or logo_paths.get("lidom"), 62, 204, 66, 32)
    c.setFillColor(colors.HexColor(highlight_text))
    c.setFont("Helvetica-Bold", 10)
    c.drawString(132, 226, f"{team_short_name(selected_team).upper()} BASERUNNING SNAPSHOT")
    c.setFont("Helvetica-Bold", 9)
    c.drawString(132, 209, f"SB: #{sb_r or '-'} ({format_value('SB', sb_v) if sb_v is not None else '-'})   |   CS: #{cs_r or '-'} ({format_value('CS', cs_v) if cs_v is not None else '-'})   |   SB%: #{sbp_r or '-'} ({format_value('SB%', sbp_v) if sbp_v is not None else '-'})")

    draw_summary_box(
        c,
        f"{team_short_name(selected_team)} Baserunning Summary",
        make_team_summary("baserunning", hitting, baserunning, selected_team),
        96,
        82,
        W - 192,
        88,
        logo_paths,
        selected_team,
    )
    draw_footer(c, 2, logo_paths, footer_bg, selected_team)
    c.showPage()

    # Page 3 - Rolling performance, larger key charts only
    draw_header(c, f"{league_display} TEAM ROLLING PERFORMANCE", f"Rolling Cumulative Charts - {date_txt}", primary, logo_paths, "blue", accent=accent, text_color=header_text, run_env_text=run_env_text)
    draw_section_title(c, "HITTING METRICS (Rolling Cumulative)   ★", 30, H - 120, section_color)
    safe_draw_image(c, logo_paths.get("baserunning"), 30, 213, 16, 16)
    draw_section_title(c, "BASERUNNING METRICS (Rolling Cumulative)   ★", 52, 226, accent)
    draw_chart_grid(c, rolling_hitting, rolling_baserunning, 38, 82, W - 76, 390, logo_paths, selected_team)
    draw_summary_box(
        c,
        f"{team_short_name(selected_team)} Team Rolling Summary",
        make_team_summary("rolling", hitting, baserunning, selected_team),
        535,
        100,
        235,
        125,
        logo_paths,
        selected_team,
    )
    draw_footer(c, 3, logo_paths, footer_bg, selected_team)
    c.showPage()

    def draw_pitching_leaderboard_page(page_num, page_title, pitching_df, empty_message, summary_title):
        draw_header(c, page_title, date_txt, primary, logo_paths, "blue", accent=accent, text_color=header_text, run_env_text=run_env_text)
        draw_section_title(c, "PITCHING LEADERBOARDS BY CATEGORY   ★", 24, H - 119, section_color)

        if pitching_df is None or pitching_df.empty:
            c.setFillColor(colors.HexColor("#444444"))
            c.setFont("Helvetica-Bold", 14)
            c.drawCentredString(W / 2, H / 2, empty_message)
        else:
            p_left = 42
            p_top = H - 148
            p_gap_x = 20
            p_gap_y = 14
            p_table_w = (W - 2 * p_left - 2 * p_gap_x) / 3
            p_table_h = 126
            for idx, stat in enumerate(PITCHING_STATS):
                row = idx // 3
                col = idx % 3
                x = p_left + col * (p_table_w + p_gap_x)
                y = p_top - (row + 1) * p_table_h - row * p_gap_y
                draw_stat_table(
                    c,
                    pitching_df,
                    stat,
                    x,
                    y,
                    p_table_w,
                    p_table_h,
                    logo_paths,
                    theme=primary,
                    ascending=pitching_lower_is_better(stat),
                    selected_team=selected_team,
                    highlight_bg=highlight_bg,
                    highlight_text=highlight_text,
                    table_text=table_text,
                )
            draw_summary_box(
                c,
                f"{team_short_name(selected_team)} {summary_title}",
                make_team_pitching_summary(pitching_df, selected_team),
                p_left + (p_table_w + p_gap_x),
                62,
                (p_table_w * 2) + p_gap_x,
                94,
                logo_paths,
                selected_team,
            )
        draw_footer(c, page_num, logo_paths, footer_bg, selected_team)
        c.showPage()

    # Page 4 - Starting pitching category leaderboards from Lidom Draft SP snapshot
    draw_pitching_leaderboard_page(
        4,
        f"{league_display} TEAM STARTING PITCHING LEADERBOARDS",
        pitching_sp,
        "Upload the Lidom Draft SP CSV to generate this page.",
        "Starting Pitching Summary",
    )

    # Page 5 - Relief pitching category leaderboards from Lidom Draft RP snapshot
    draw_pitching_leaderboard_page(
        5,
        f"{league_display} TEAM RELIEF PITCHING LEADERBOARDS",
        pitching_rp,
        "Upload the Lidom Draft RP CSV to generate this page.",
        "Relief Pitching Summary",
    )

    # Page 6 - Defense category leaderboards from catcher, infield, and outfield snapshots
    draw_header(c, f"{league_display} TEAM DEFENSE LEADERBOARDS", date_txt, primary, logo_paths, "red", accent=accent, text_color=header_text, run_env_text=run_env_text)
    draw_section_title(c, "DEFENSE LEADERBOARDS BY CATEGORY   ★", 24, H - 119, section_color)

    if defense is None or defense.empty:
        c.setFillColor(colors.HexColor("#444444"))
        c.setFont("Helvetica-Bold", 14)
        c.drawCentredString(W / 2, H / 2, "Upload 2022 Game Review, Infield Counting, and Outfield Counting CSVs to generate this page.")
    else:
        d_left = 34
        d_top = H - 148
        d_gap_x = 18
        d_gap_y = 16
        d_table_w = (W - 2 * d_left - 2 * d_gap_x) / 3
        d_table_h = 142
        d_stats = ["CS%", "IFErr", "IFFld%", "OFErr", "OFFld%"]
        for idx, stat in enumerate(d_stats):
            row = idx // 3
            col = idx % 3
            x = d_left + col * (d_table_w + d_gap_x)
            y = d_top - (row + 1) * d_table_h - row * d_gap_y
            draw_stat_table(
                c,
                defense,
                stat,
                x,
                y,
                d_table_w,
                d_table_h,
                logo_paths,
                theme=primary,
                ascending=defense_lower_is_better(stat),
                selected_team=selected_team,
                highlight_bg=highlight_bg,
                highlight_text=highlight_text,
                table_text=table_text,
            )
        draw_summary_box(
            c,
            f"{team_short_name(selected_team)} Defense Summary",
            make_team_defense_summary(defense, selected_team),
            d_left + 2 * (d_table_w + d_gap_x),
            d_top - 2 * d_table_h - d_gap_y,
            d_table_w,
            d_table_h,
            logo_paths,
        selected_team,
        )
    draw_footer(c, 6, logo_paths, footer_bg, selected_team)
    c.save()
    output.seek(0)
    return output


def safe_filename(name: str) -> str:
    """Safe PDF filename for each report POV."""
    cleaned = re.sub(r"[^A-Za-z0-9_-]+", "_", str(name).strip())
    cleaned = re.sub(r"_+", "_", cleaned).strip("_")
    return cleaned or "Team"


def build_all_team_pdfs_zip(hitting, baserunning, rolling_hitting, rolling_baserunning, pitching_sp, pitching_rp, defense, logo_uploads, team_list, selected_league="LIDOM", run_env_text=None) -> bytes:
    """Create a ZIP containing one PDF per selected/reportable team in the selected league."""
    zip_buffer = BytesIO()
    with zipfile.ZipFile(zip_buffer, "w", compression=zipfile.ZIP_DEFLATED) as zf:
        for team in team_list:
            pdf_buffer = to_pdf(
                hitting,
                baserunning,
                rolling_hitting,
                rolling_baserunning,
                pitching_sp,
                pitching_rp,
                defense,
                logo_uploads,
                team,
                selected_league,
                run_env_text,
            )
            pdf_buffer.seek(0)
            prefix = LEAGUE_CONFIG.get(selected_league, LEAGUE_CONFIG["LIDOM"]).get("zip_prefix", "Team_Report")
            zf.writestr(f"{prefix}_{safe_filename(team_short_name(team))}.pdf", pdf_buffer.getvalue())
    zip_buffer.seek(0)
    return zip_buffer.getvalue()



